{{ $json['  Do you have any known allergies?  if yes, please describe'] }}


Please assess the medical risk level based on this information and return structured JSON as instructed.

parameters.jsCode:
// Get raw output string
const rawOutput = $json.output;

// Safety check
if (!rawOutput) {
  throw new Error("No AI output found.");
}

let parsed;

// Try parsing JSON safely
try {
  parsed = JSON.parse(rawOutput);
} catch (error) {
  throw new Error("AI output is not valid JSON.");
}

// Normalize risk level formatting
const normalizedRisk = parsed.risk_level?.trim() || "Unknown";

// Ensure boolean values
const requiresImmediateAttention = Boolean(parsed.requires_immediate_attention);
const allergyFlag = Boolean(parsed.allergy_flag);
const medicationConflictRisk = Boolean(parsed.medication_conflict_risk);

// Normalize confidence score
let confidence = Number(parsed.confidence_score);
if (isNaN(confidence)) {
  confidence = 0;
}

// Return clean structured JSON
return [
  {
    json: {
      risk_level: normalizedRisk,
      requires_immediate_attention: requiresImmediateAttention,
      allergy_flag: allergyFlag,
      medication_conflict_risk: medicationConflictRisk,
      key_concerns: parsed.key_concerns || [],
      doctor_preparation_notes: parsed.doctor_preparation_notes || "",
      confidence_score: confidence
    }
  }
];

